challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The RAN has completely detached from the core network. This is likely due to a failure of the gNB itself or a network partition severing the N2 (control plane) and N3 (user plane) interfaces to the AMF and UPF respectively.",
      "primary_suspect_nf": "amf",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "from: amf, to_ip: gnb_n2_ip",
          "expected_if_hypothesis_holds": "High or 100% packet loss, indicating a network partition or gNB unreachability.",
          "falsifying_observation": "Low RTT (<5ms) and no packet loss. This would indicate the network path is healthy and the gNB is responsive at the network layer, making a simple partition unlikely."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: upf, to_ip: gnb_n3_ip",
          "expected_if_hypothesis_holds": "High or 100% packet loss, consistent with a gNB failure or network partition affecting all paths to the gNB.",
          "falsifying_observation": "Low RTT (<5ms). This would falsify a full gNB failure and suggest the issue is specific to the AMF-gNB path (N2 interface)."
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "container: nr-gnb",
          "expected_if_hypothesis_holds": "No process listening on the SCTP port for N2 or the UDP port for N3, indicating a crashed or misconfigured gNB process.",
          "falsifying_observation": "Processes are listening on the correct SCTP (N2) and GTP-U (N3) ports. This proves the gNB process is running and ready for connections."
        }
      ],
      "notes": "This plan focuses on testing the 'network partition' and 'gNB failure' aspects of the hypothesis by checking network reachability from multiple core NFs (triangulation) and verifying the gNB process status directly."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "The AMF has an internal fault that caused it to drop all N2 associations to the gNBs, even though the process itself is still running. This would lead to a full detachment of all UEs.",
      "primary_suspect_nf": "amf",
      "probes": [
        {
          "tool": "check_process_listeners",
          "args_hint": "container: amf",
          "expected_if_hypothesis_holds": "A process is listening on the N2/SCTP port, but is otherwise non-functional.",
          "falsifying_observation": "No process is listening on the N2/SCTP port. This would mean the AMF process has crashed, contradicting the hypothesis that it is 'still running'."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "nf: amf, metrics: ['sctp_errors', 'ngap_errors']",
          "expected_if_hypothesis_holds": "Elevated counters for SCTP or NGAP protocol errors, indicating the AMF is failing to process messages correctly.",
          "falsifying_observation": "Zero or nominal error counts. This would suggest the AMF is not experiencing any internal processing errors, weakening the 'internal fault' hypothesis."
        },
        {
          "tool": "get_network_status",
          "args_hint": "component: amf",
          "expected_if_hypothesis_holds": "The link status to the gNB (N2) should appear 'ACTIVE', as the issue is an internal AMF fault, not a lower-level link failure.",
          "falsifying_observation": "The link status to the gNB (N2) is 'INACTIVE'. This points to a network-level problem, falsifying the idea that the fault is contained entirely within the AMF application."
        }
      ],
      "notes": "This plan attempts to isolate the failure to the AMF process itself. It verifies the process is running but likely faulty by checking for internal protocol errors while confirming the underlying network links are not the cause."
    },
    {
      "hypothesis_id": "h3",
      "hypothesis_statement": "UEs detaching, sessions torn down \u2014 RAN-triggered",
      "primary_suspect_nf": "smf",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "from: smf, to_ip: upf_n4_ip",
          "expected_if_hypothesis_holds": "Low RTT and no packet loss, as the trigger is from the RAN, not from a core network path failure between SMF and UPF.",
          "falsifying_observation": "High or 100% packet loss. This would indicate a failure in the core N4 path, suggesting a core-triggered issue, not a RAN-triggered one."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "nf: nr-gnb, metrics: ['rrc_connection_failures', 'initial_attach_failures']",
          "expected_if_hypothesis_holds": "Metrics indicating the gNB is what triggered the detachment, such as a high count of RRC connection releases or failures.",
          "falsifying_observation": "Zero or nominal gNB-level failure counts. If the gNB is not showing any signs of actively tearing down connections, the trigger is unlikely to be from the RAN."
        },
        {
          "tool": "query_subscriber",
          "args_hint": "imsi: <known_imsi>",
          "expected_if_hypothesis_holds": "The subscriber is shown as 'DEREGISTERED' in the UDM/HSS, consistent with a full detachment procedure originating from the RAN.",
          "falsifying_observation": "The subscriber is still shown as 'REGISTERED'. This would indicate a 'ghost' state where the AMF has lost the UE session but the core (UDM) has not been updated, pointing away from a clean RAN-triggered detach."
        }
      ],
      "notes": "This plan focuses on verifying the 'RAN-triggered' nature of the event. It checks for core network faults that could be an alternative cause and looks for positive evidence at the gNB and in the UDM that a RAN-initiated procedure actually occurred."
    }
  ]
}

